.grid-container {
  display: flex;
  flex-direction: column;   /* stack options vertically */
  gap: 20px;                /* space between options */
  max-width: 500px;
  margin: 0 auto;
}

.option {
  display: flex;            /* label + image in a row */
  align-items: center;      /* vertically center image with label */
}

.option-label {
  font-weight: bold;
  font-size: 18px;
  width: 30px;              /* fixed width for labels */
  margin-right: 10px;       /* space between label and image */
  text-align: left;
}

.option img {
  width: 100%;              /* image fills remaining space */
  max-width: 400px;         /* optional */
  height: auto;             /* maintain aspect ratio */
  border: 1px solid #ccc;
}

